import java.io.InputStream;
import java.net.MalformedURLException;
import java.net.URL;
import java.net.URLConnection;
import java.nio.charset.StandardCharsets;

/**
 * Service to fetch a preview of a URL's content.
 * Returns the first 1 KB of the page as a preview string.
 */
public class UrlPreviewService {

    private static final int TIMEOUT_MS = 5000;
    private static final int PREVIEW_SIZE = 1024; // 1 KB

    /**
     * Retrieves a preview (first 1 KB) of the content at the given URL.
     *
     * @param urlString the URL to fetch
     * @return the preview text, or an empty string if the request fails or the URL is invalid
     */
    public String getUrlContentPreview(String urlString) {
        if (urlString == null || urlString.isEmpty()) {
            return "";
        }

        URL url;
        try {
            url = new URL(urlString);
        } catch (MalformedURLException e) {
            return "";
        }

        // Only allow HTTP and HTTPS to avoid file:/// or other dangerous protocols
        String scheme = url.getProtocol();
        if (!"http".equalsIgnoreCase(scheme) && !"https".equalsIgnoreCase(scheme)) {
            return "";
        }

        URLConnection connection;
        try {
            connection = url.openConnection();
            connection.setConnectTimeout(TIMEOUT_MS);
            connection.setReadTimeout(TIMEOUT_MS);
            // Set a common User‑Agent to reduce the chance of being blocked
            connection.setRequestProperty("User-Agent", "Mozilla/5.0");

            try (InputStream in = connection.getInputStream()) {
                byte[] buffer = new byte[PREVIEW_SIZE];
                int totalRead = 0;
                int read;
                while (totalRead < PREVIEW_SIZE && (read = in.read(buffer, totalRead, PREVIEW_SIZE - totalRead)) != -1) {
                    totalRead += read;
                }
                return new String(buffer, 0, totalRead, StandardCharsets.UTF_8);
            }
        } catch (IOException e) {
            // Any network error, timeout, or HTTP error status results in an empty preview
            return "";
        }
    }
}

